update public.lessons l set enhancements = $ench${"industryStory":"The UI looked fine but orders silently failed — the API behind \"Place order\" returned an error the UI swallowed. A tester who could check the API directly found it in minutes. A lot of real behaviour (and real bugs) lives at the API layer.","visualAid":{"type":"comparison","title":"HTTP methods & common status codes","headers":["Code / Method","Meaning"],"rows":[["GET / POST","Read / create"],["PUT-PATCH / DELETE","Update / remove"],["200 / 201","OK / Created"],["400 / 401 / 404","Bad request / Unauthorised / Not found"],["500","Server error"]]},"davidTip":"Know your status codes cold — they come up constantly in interviews and daily work. But never stop at the status: a 200 with the wrong body is still a bug.","miniChallenge":"For create/fetch/update/delete a user, name the method and the success status code you'd expect.","modelAnswer":"## Example\nCreate → POST → 201; Fetch → GET → 200; Update → PUT/PATCH → 200; Delete → DELETE → 200 or 204."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'practical-test-automation-playwright'
  and m.module_number = 8 and l.lesson_number = 1;

update public.lessons l set enhancements = $ench${"industryStory":"A team did all their setup through slow UI clicks until they discovered Playwright's request fixture — fast, stable API tests with no browser. Their suite got quicker and less flaky overnight.","davidTip":"API tests are the fastest, most stable tests you can write in Playwright. Reach for the request fixture whenever a check doesn't truly need the browser — and always await both the request and the json() parse.","miniChallenge":"Write a Playwright API test that GETs a public endpoint and asserts the status and one field of the body.","modelAnswer":"## Example\ntest('gets a post', async ({ request }) => { const res = await request.get('/posts/1'); expect(res.status()).toBe(200); const body = await res.json(); expect(body.id).toBe(1); });","resourcePreview":{"name":"API Testing with Playwright Template","purpose":"Test APIs directly and combine them with UI tests.","whenToUse":"Use it as the pattern for your API tests.","formats":["PDF","DOCX"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'practical-test-automation-playwright'
  and m.module_number = 8 and l.lesson_number = 2;

update public.lessons l set enhancements = $ench${"industryStory":"Every API test logged in again, making the suite slow and noisy. Acquiring a token once in setup and reusing it via a fixture sped everything up — and kept credentials out of the test code.","davidTip":"Acquire auth once and reuse it (token in a fixture/setup), rather than logging in per test. Store credentials in environment variables, never in code — repeated logins are slow and hard-coded secrets are a liability.","miniChallenge":"Outline how you'd authenticate once and reuse the token across several API tests.","modelAnswer":"## Example\nA setup step POSTs to /login with env credentials, captures the token, and a fixture attaches it as an Authorization header to every request — so tests run authenticated without repeating the login."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'practical-test-automation-playwright'
  and m.module_number = 8 and l.lesson_number = 3;

update public.lessons l set enhancements = $ench${"industryStory":"An API test only checked \"status is 200\" and missed that the endpoint returned an empty list when it should have returned results. Strong assertions check the things that actually matter, including the error cases.","badGood":{"label":"an API assertion","bad":"expect(res.status()).toBe(200); // and nothing else","good":"expect(res.status()).toBe(201); expect(body.id).toBeDefined(); expect(body.total).toBe(120); // + a 400 case for bad input"},"davidTip":"A response can be \"200 OK\" and still wrong. Assert the fields and shape that matter, and test the error/negative cases (400, 401, 404) too — status alone is the weakest possible check.","miniChallenge":"For a \"create order\" endpoint, write assertions: status, one key field, and a negative case for invalid input.","modelAnswer":"## Example\nValid: status 201, body.id exists, body.total equals expected. Negative: an invalid payload returns 400; an unauthenticated request returns 401."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'practical-test-automation-playwright'
  and m.module_number = 8 and l.lesson_number = 4;

update public.lessons l set enhancements = $ench${"industryStory":"A UI test wasted minutes clicking through a multi-step sign-up just to reach the account page. Creating the account via the API first, then driving only the behaviour under test through the UI, made it fast and stable.","davidTip":"The fastest UI tests do their setup via the API. Create the data you need with request.post, drive only the behaviour under test through the UI, and tear down via the API afterwards.","miniChallenge":"Take a UI test with slow setup and redesign it to create its starting state via the API.","modelAnswer":"## Example\nTo test the account page, the test creates the account via POST /users, then the UI test just logs in and checks the page — instead of clicking through the whole sign-up flow first.","portfolioBuilder":"Including API tests plus API-driven setup in your capstone shows you test beyond the UI and build fast, stable suites — a strong differentiator.","resourcePreview":{"name":"API Testing with Playwright Template","purpose":"Standalone API tests and using the API to seed UI tests.","whenToUse":"Use it for the API portion of your capstone.","formats":["PDF","DOCX"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'practical-test-automation-playwright'
  and m.module_number = 8 and l.lesson_number = 5;

